              const previewDates=()=>{if(!schedStart)return[];try{return computeScheduleDates(schedPattern,schedStart);}catch{return[];}};
              return(
                <div style={{background:C.card,border:`1px solid ${C.border}`,borderRadius:12,padding:20}}>
